1	import { InferSchema, lazySchema, zodSchema } from '@ai-sdk/provider-utils';
2	import { z } from 'zod/v4';
3	
4	export const falImageModelOptionsSchema = lazySchema(() =>
5	  zodSchema(
6	    z
7	      .object({
8	        /** @deprecated use prompt.images instead */
9	        imageUrl: z.string().nullish().meta({
10	          deprecated: true,
11	          description: 'Use `prompt.images` instead',
12	        }),
13	        maskUrl: z
14	          .string()
15	          .nullish()
16	          .meta({ deprecated: true, description: 'Use `prompt.mask` instead' }),
17	        guidanceScale: z.number().min(1).max(20).nullish(),
18	        numInferenceSteps: z.number().min(1).max(50).nullish(),
19	        enableSafetyChecker: z.boolean().nullish(),
20	        outputFormat: z.enum(['jpeg', 'png']).nullish(),
21	        syncMode: z.boolean().nullish(),
22	        strength: z.number().nullish(),
23	        acceleration: z.enum(['none', 'regular', 'high']).nullish(),
24	        safetyTolerance: z
25	          .enum(['1', '2', '3', '4', '5', '6'])
26	          .or(z.number().min(1).max(6))
27	          .nullish(),
28	        /**
29	         * When true, converts multiple input images to `image_urls` array instead of `image_url` string.
30	         */
31	        useMultipleImages: z.boolean().nullish(),
32	
33	        // Deprecated snake_case versions
34	        image_url: z.string().nullish(),
35	        mask_url: z.string().nullish(),
36	        guidance_scale: z.number().min(1).max(20).nullish(),
37	        num_inference_steps: z.number().min(1).max(50).nullish(),
38	        enable_safety_checker: z.boolean().nullish(),
39	        output_format: z.enum(['jpeg', 'png']).nullish(),
40	        sync_mode: z.boolean().nullish(),
41	        safety_tolerance: z
42	          .enum(['1', '2', '3', '4', '5', '6'])
43	          .or(z.number().min(1).max(6))
44	          .nullish(),
45	      })
46	      .passthrough()
47	      .transform(data => {
48	        const result: Record<string, unknown> = {};
49	        const deprecatedKeys: string[] = [];
50	
51	        const mapKey = (snakeKey: string, camelKey: string) => {
52	          const snakeValue = data[snakeKey as keyof typeof data];
53	          const camelValue = data[camelKey as keyof typeof data];
54	
55	          // If snake_case is used, mark it as deprecated
56	          if (snakeValue !== undefined && snakeValue !== null) {
57	            deprecatedKeys.push(snakeKey);
58	            result[camelKey] = snakeValue;
59	          } else if (camelValue !== undefined && camelValue !== null) {
60	            result[camelKey] = camelValue;
61	          }
62	        };
63	
64	        // Map all known parameters
65	        mapKey('image_url', 'imageUrl');
66	        mapKey('mask_url', 'maskUrl');
67	        mapKey('guidance_scale', 'guidanceScale');
68	        mapKey('num_inference_steps', 'numInferenceSteps');
69	        mapKey('enable_safety_checker', 'enableSafetyChecker');
70	        mapKey('output_format', 'outputFormat');
71	        mapKey('sync_mode', 'syncMode');
