## Comprehensive Analysis of Vercel AI SDK Provider Package Structure

Based on my thorough exploration of the monorepo, here's everything you need to understand to create a new provider package from scratch:

---

### 1. DIRECTORY STRUCTURE & CORE FILES

Every provider package follows this consistent structure:

```
packages/[provider-name]/
├── src/
│   ├── index.ts                          # Main export file
│   ├── version.ts                         # Version management
│   ├── [provider]-provider.ts             # Factory function + interface
│   ├── [provider]-provider.test.ts        # Provider factory tests
│   ├── [model-type]/                      # Organized by model type
│   │   ├── [provider]-[model]-model.ts
│   │   ├── [provider]-[model]-model.test.ts
│   │   ├── [provider]-[model]-options.ts
│   │   ├── [provider]-[model]-settings.ts
│   │   └── [provider]-[model]-api.ts      # API schema definitions
│   ├── [provider]-config.ts               # Optional: shared config
│   └── [provider]-error.ts                # Optional: error handling
├── package.json
├── tsconfig.json
├── tsconfig.build.json
├── tsup.config.ts                        # Build configuration
├── vitest.node.config.js                 # Node environment tests
├── vitest.edge.config.js                 # Edge environment tests
├── turbo.json                            # Turborepo config
├── README.md
└── CHANGELOG.md
```

---

### 2. PACKAGE.JSON TEMPLATE

```json
{
  "name": "@ai-sdk/[provider]",
  "version": "1.0.0",
  "license": "Apache-2.0",
  "sideEffects": false,
  "main": "./dist/index.js",
  "module": "./dist/index.mjs",
  "types": "./dist/index.d.ts",
  "files": [
    "dist/**/*",
    "docs/**/*",
    "src",
    "!src/**/*.test.ts",
    "!src/**/*.test-d.ts",
    "!src/**/__snapshots__",
    "!src/**/__fixtures__",
    "CHANGELOG.md",
    "README.md"
  ],
  "scripts": {
    "build": "pnpm clean && tsup --tsconfig tsconfig.build.json",
    "build:watch": "pnpm clean && tsup --watch",
    "clean": "del-cli dist docs *.tsbuildinfo",
    "prepack": "mkdir -p docs && cp ../../content/providers/01-ai-sdk-providers/XX-provider.mdx ./docs/",
    "postpack": "del-cli docs",
    "type-check": "tsc --build",
    "test": "pnpm test:node && pnpm test:edge",
    "test:update": "pnpm test:node -u",
    "test:watch": "vitest --config vitest.node.config.js",
    "test:edge": "vitest --config vitest.edge.config.js --run",
    "test:node": "vitest --config vitest.node.config.js --run"
  },
  "exports": {
    "./package.json": "./package.json",
    ".": {
      "types": "./dist/index.d.ts",
      "import": "./dist/index.mjs",
      "require": "./dist/index.js"
    }
  },
  "dependencies": {
    "@ai-sdk/provider": "workspace:*",
    "@ai-sdk/provider-utils": "workspace:*"
  },
  "devDependencies": {
    "@ai-sdk/test-server": "workspace:*",
    "@types/node": "20.17.24",
    "@vercel/ai-tsconfig": "workspace:*",
    "tsup": "^8",
    "typescript": "5.8.3",
    "zod": "3.25.76"
  },
  "peerDependencies": {
    "zod": "^3.25.76 || ^4.1.8"
  },
  "engines": {
    "node": ">=18"
  },
  "publishConfig": {
    "access": "public"
  }
}
```

---

### 3. PROVIDER FACTORY PATTERN

The core file is `[provider]-provider.ts`. It defines:

**Interface Definition:**
```typescript
export interface YourProviderSettings {
  // Required for authentication
  apiKey?: string;

  // Optional overrides
  baseURL?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
  // Other provider-specific settings
}

export interface YourProvider extends ProviderV3 {
  // Factory methods for each model type
  imageModel(modelId: YourImageModelId): ImageModelV3;
  image(modelId: YourImageModelId): ImageModelV3; // alias

  languageModel(modelId: string): LanguageModelV3;
  embeddingModel(modelId: string): EmbeddingModelV3;
  // ... other methods as needed
}
```

**Factory Function:**
```typescript
export function createYourProvider(options: YourProviderSettings = {}): YourProvider {
  // 1. Setup base URL with trailing slash handling
  const baseURL = withoutTrailingSlash(options.baseURL ?? 'https://api.provider.com');

  // 2. Create getHeaders function that loads API key and adds user agent
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'YOUR_PROVIDER_API_KEY',
          description: 'Your Provider',
        })}`,
        ...options.headers,
      },
      `ai-sdk/your-provider/${VERSION}`,
    );

  // 3. Create model factory functions
  const createImageModel = (modelId: YourImageModelId) =>
    new YourImageModel(modelId, {
      provider: 'yourprovider.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  // 4. Return provider object with spec version and all factory methods
  return {
    specificationVersion: 'v3' as const,
    imageModel: createImageModel,
    image: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'languageModel',
      });
    },
    embeddingModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'embeddingModel',
      });
    },
    // ... other methods
  };
}

// Export default instance
export const yourProvider = createYourProvider();
```

**Key utilities from `@ai-sdk/provider-utils`:**
- `loadApiKey()` - Loads from options or environment with fallback
- `loadOptionalSetting()` - For optional settings
- `withoutTrailingSlash()` - Normalizes URLs
- `withUserAgentSuffix()` - Adds SDK identifier to user agent
- `combineHeaders()` - Merges header objects

---

### 4. IMAGE MODEL IMPLEMENTATION (ImageModelV3)

**Interface Requirements** (from `@ai-sdk/provider`):

```typescript
export type ImageModelV3 = {
  readonly specificationVersion: 'v3';
  readonly provider: string;
  readonly modelId: string;
  readonly maxImagesPerCall: number | undefined | GetMaxImagesPerCallFunction;

  doGenerate(options: ImageModelV3CallOptions): PromiseLike<{
    images: Array<string> | Array<Uint8Array>; // base64 or binary
    warnings: Array<SharedV3Warning>;
    providerMetadata?: ImageModelV3ProviderMetadata;
    response: {
      timestamp: Date;
      modelId: string;
      headers: Record<string, string> | undefined;
    };
    usage?: ImageModelV3Usage;
  }>;
};
```

**Call Options:**
```typescript
export type ImageModelV3CallOptions = {
  prompt: string | undefined;
  n: number; // Number of images
  size: `${number}x${number}` | undefined; // e.g., "1024x1024"
  aspectRatio: `${number}:${number}` | undefined; // e.g., "16:9"
  seed: number | undefined;
  files: ImageModelV3File[] | undefined; // For image editing
  mask: ImageModelV3File | undefined; // For inpainting
  providerOptions: SharedV3ProviderOptions; // Provider-specific options
  abortSignal?: AbortSignal;
  headers?: Record<string, string | undefined>;
};
```

**File Types:**
```typescript
export type ImageModelV3File =
  | {
      type: 'file';
      mediaType: string; // e.g., "image/png"
      data: string | Uint8Array; // base64 or binary
      providerOptions?: SharedV3ProviderMetadata;
    }
  | {
      type: 'url';
      url: string;
      providerOptions?: SharedV3ProviderMetadata;
    };
```

---

### 5. COMPLETE IMAGE MODEL EXAMPLE (fal-image-model.ts pattern)

```typescript
import {
  ImageModelV3,
  ImageModelV3File,
  SharedV3Warning,
} from '@ai-sdk/provider';
import {
  FetchFunction,
  combineHeaders,
  convertImageModelFileToDataUri,
  createJsonResponseHandler,
  createJsonErrorResponseHandler,
  postJsonToApi,
  parseProviderOptions,
  resolve,
} from '@ai-sdk/provider-utils';
import { z } from 'zod';

interface YourImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class YourImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1; // Or more depending on API

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: string,
    private readonly config: YourImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const warnings: Array<SharedV3Warning> = [];

    // 1. Parse and validate provider-specific options
    const providerOptions = await parseProviderOptions({
      provider: 'yourprovider',
      providerOptions: options.providerOptions,
      schema: yourImageModelOptionsSchema, // Zod schema
    });

    // 2. Build API request body
    const requestBody: Record<string, unknown> = {
      prompt: options.prompt,
      model: this.modelId,
      n: options.n,
      // ... transform size/aspectRatio to provider format
      // ... handle files (image editing)
      // ... handle mask (inpainting)
    };

    // Add provider options to request
    if (providerOptions) {
      for (const [key, value] of Object.entries(providerOptions)) {
        if (value !== undefined) {
          requestBody[key] = value;
        }
      }
    }

    // 3. Make API request
    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/${this.modelId}`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        options.headers,
      ),
      body: requestBody,
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: yourErrorSchema,
        errorToMessage: (error) => error.message,
      }),
      successfulResponseHandler: createJsonResponseHandler(yourResponseSchema),
      abortSignal: options.abortSignal,
      fetch: this.config.fetch,
    });

    // 4. Download images if URLs returned
    const images = await Promise.all(
      value.images.map((img) => this.downloadImage(img.url, options.abortSignal)),
    );

    // 5. Return standardized result
    return {
      images,
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
      providerMetadata: {
        yourprovider: {
          images: value.images,
          // ... other metadata
        },
      },
    };
  }

  private async downloadImage(
    url: string,
    abortSignal: AbortSignal | undefined,
  ): Promise<Uint8Array> {
    const { value: response } = await getFromApi({
      url,
      abortSignal,
      failedResponseHandler: createStatusCodeErrorResponseHandler(),
      successfulResponseHandler: createBinaryResponseHandler(),
      fetch: this.config.fetch,
    });
    return response;
  }
}
```

---

### 6. PROVIDER OPTIONS SCHEMA (Zod Pattern)

**Image options example (fal-image-options.ts):**

```typescript
import { lazySchema, zodSchema, InferSchema } from '@ai-sdk/provider-utils';
import { z } from 'zod';

export const yourImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      // Typical image generation options
      guidance_scale: z.number().min(1).max(20).nullish(),
      num_inference_steps: z.number().min(1).max(50).nullish(),
      safety_checker: z.boolean().nullish(),
      output_format: z.enum(['jpeg', 'png']).nullish(),

      // Provider-specific options
      customOption1: z.string().nullish(),
      customOption2: z.number().nullish(),
    })
    .passthrough() // Allow additional properties
    .transform((data) => {
      // Normalize option names if needed
      const result: Record<string, unknown> = {};
      for (const [key, value] of Object.entries(data)) {
        if (value !== undefined && value !== null) {
          result[key] = value;
        }
      }
      return result;
    }),
  ),
);

export type YourImageModelOptions = InferSchema<
  typeof yourImageModelOptionsSchema
>;
```

---

### 7. MODEL SETTINGS (Model ID Union Types)

**Pattern (fal-image-settings.ts):**

```typescript
export type YourImageModelId =
  | 'model-id-1'
  | 'model-id-2'
  | 'model-id-3'
  | (string & {}); // Allows any string as fallback

export type YourImageSize =
  | 'square'
  | 'landscape_16_9'
  | 'portrait_16_9'
  | {
      width: number;
      height: number;
    };
```

---

### 8. MAIN ENTRY POINT (index.ts)

```typescript
