  YourImageModel: vi.fn(),
}));

describe('createYourProvider', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('should create image model with default config', () => {
    const provider = createYourProvider();
    const modelId = 'model-id-1';

    provider.image(modelId);

    expect(YourImageModel).toHaveBeenCalledWith(
      modelId,
      expect.objectContaining({
        provider: 'yourprovider.image',
        baseURL: 'https://api.provider.com',
      }),
    );
  });

  it('should respect custom options', () => {
    const provider = createYourProvider({
      apiKey: 'custom-key',
      baseURL: 'https://custom.provider.com',
      headers: { 'X-Custom': 'header' },
    });

    provider.image('model-id-1');

    expect(YourImageModel).toHaveBeenCalledWith(
      expect.any(String),
      expect.objectContaining({
        baseURL: 'https://custom.provider.com',
        headers: expect.any(Function),
      }),
    );
  });
