### 13. ADVANCED PATTERNS

**Polling Pattern (used by Luma for async jobs):**
```typescript
async pollForResult(
  requestId: string,
  headers: Record<string, string>,
  abortSignal: AbortSignal | undefined,
  pollSettings?: { pollIntervalMillis?: number; maxPollAttempts?: number },
): Promise<string> {
  const maxPollAttempts = pollSettings?.maxPollAttempts ?? 120;
  const pollIntervalMillis = pollSettings?.pollIntervalMillis ?? 500;

  for (let i = 0; i < maxPollAttempts; i++) {
    const { value: statusResponse } = await getFromApi({
      url: `${this.config.baseURL}/result/${requestId}`,
      headers,
      abortSignal,
      failedResponseHandler: createJsonErrorResponseHandler({ ... }),
      successfulResponseHandler: createJsonResponseHandler(resultSchema),
      fetch: this.config.fetch,
    });

    if (statusResponse.state === 'completed') {
      return statusResponse.result;
    }

    if (statusResponse.state === 'failed') {
      throw new Error(`Job failed: ${statusResponse.error}`);
    }

    await delay(pollIntervalMillis);
  }

  throw new Error(`Polling timed out after ${maxPollAttempts} attempts`);
}
