  const pollIntervalMillis = pollSettings?.pollIntervalMillis ?? 500;

  for (let i = 0; i < maxPollAttempts; i++) {
    const { value: statusResponse } = await getFromApi({
      url: `${this.config.baseURL}/result/${requestId}`,
      headers,
      abortSignal,
