import { z } from 'zod/v4';

/**
 * Provider options schema for PixelArt image generation.
 *
 * @see https://api.pixelart.ai/v1/docs
 */
export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z
      .object({
        /**
         * The artistic style for the generated image.
         *
         * - `pixel`: Classic pixel art style with sharp edges and vibrant colors
         * - `retro`: Retro gaming aesthetic with a limited color palette
         * - `8bit`: 8-bit video game style with chunky, blocky pixels
         *
         * @default undefined (the model's default style is used)
         */
        style: z.enum(['pixel', 'retro', '8bit']).nullish(),

        /**
         * The pixel density for the pixel art effect. Controls the size of
         * individual "pixel cells" in the output image. Higher values produce
         * a more blocky, pixelated appearance; lower values are subtler.
         *
         * Range: 1–16. Default: 4.
         */
        pixelDensity: z.number().int().min(1).max(16).nullish(),
      })
      .passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

