import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  FetchFunction,
  InferSchema,
  combineHeaders,
  createBinaryResponseHandler,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  createStatusCodeErrorResponseHandler,
  getFromApi,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { pixelArtImageModelOptionsSchema } from './pixelart-image-options';

const DEFAULT_SIZE = '512x512';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: string,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
    files,
    mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (seed != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'seed',
        details: 'PixelArt does not support the `seed` option.',
      });
    }

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support the `aspectRatio` option. Use `size` instead.',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'input-files',
        details: 'PixelArt does not support image editing via input files.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'PixelArt does not support mask-based inpainting.',
      });
    }

    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const { style, pixelDensity, ...additionalOptions } =
      pixelArtOptions ?? {};

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        size: size ?? DEFAULT_SIZE,
        ...(style != null ? { style } : {}),
        ...(pixelDensity != null ? { pixel_density: pixelDensity } : {}),
        ...additionalOptions,
      },
      abortSignal,
      fetch: this.config.fetch,
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelArtErrorSchema,
        errorToMessage: (error) => error.error.message,
      }),
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtGenerationResponseSchema,
      ),
    });

    const images = await Promise.all(
      response.data.map((item) => this.downloadImage(item.url, abortSignal)),
    );

    return {
      images,
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }

  private async downloadImage(
    url: string,
    abortSignal: AbortSignal | undefined,
  ): Promise<Uint8Array> {
    const { value } = await getFromApi({
      url,
      abortSignal,
      failedResponseHandler: createStatusCodeErrorResponseHandler(),
      successfulResponseHandler: createBinaryResponseHandler(),
      fetch: this.config.fetch,
    });
    return value;
  }
}

// limited version of the schema, focused on what is needed for the implementation;
// this approach limits breakages when the API changes and increases efficiency
const pixelArtGenerationResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      created: z.number(),
      data: z.array(
        z.object({
          url: z.string(),
        }),
      ),
    }),
  ),
);

const pixelArtErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string().nullish(),
    code: z.string().nullish(),
  }),
});

export type PixelArtErrorData = z.infer<typeof pixelArtErrorSchema>;

// Re-export options type so index.ts can re-export from one place
export type { PixelArtImageModelOptions } from './pixelart-image-options';

// Suppress unused import warning – InferSchema is used via the re-export above
type _InferSchemaUnused = InferSchema<typeof pixelArtImageModelOptionsSchema>;

