import { describe, it, expect, beforeEach, vi } from 'vitest';
import { createPixelArt } from './pixelart-provider';
import { PixelArtImageModel } from './pixelart-image-model';

vi.mock('./pixelart-image-model', () => ({
  PixelArtImageModel: vi.fn(),
}));

describe('createPixelArt', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe('image', () => {
    it('should construct an image model with default configuration', () => {
      const provider = createPixelArt();
      const modelId = 'pixel-art-v1';

      const model = provider.image(modelId);

      expect(model).toBeInstanceOf(PixelArtImageModel);
      expect(PixelArtImageModel).toHaveBeenCalledWith(
        modelId,
        expect.objectContaining({
          provider: 'pixelart.image',
          baseURL: 'https://api.pixelart.ai/v1',
        }),
      );
    });

    it('should respect custom configuration options', () => {
      const customBaseURL = 'https://custom.pixelart.ai/v1';
      const customHeaders = { 'X-Custom-Header': 'value' };
      const mockFetch = vi.fn();

      const provider = createPixelArt({
        apiKey: 'custom-api-key',
        baseURL: customBaseURL,
        headers: customHeaders,
        fetch: mockFetch,
      });
      const modelId = 'pixel-art-v2';

      provider.image(modelId);

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        modelId,
        expect.objectContaining({
          baseURL: customBaseURL,
          headers: expect.any(Function),
          fetch: mockFetch,
          provider: 'pixelart.image',
        }),
      );
    });

    it('should strip a trailing slash from the base URL', () => {
      const provider = createPixelArt({
        baseURL: 'https://api.pixelart.ai/v1/',
      });

      provider.image('pixel-art-v1');

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        expect.any(String),
        expect.objectContaining({
          baseURL: 'https://api.pixelart.ai/v1',
        }),
      );
    });

    it('imageModel should be an alias for image', () => {
      const provider = createPixelArt();
      const modelId = 'pixel-art-mini';

      provider.imageModel(modelId);

      expect(PixelArtImageModel).toHaveBeenCalledWith(
        modelId,
        expect.objectContaining({
          provider: 'pixelart.image',
        }),
      );
    });
  });

  describe('unsupported model types', () => {
    it('should throw NoSuchModelError for languageModel', () => {
      const provider = createPixelArt();
      expect(() => provider.languageModel('gpt-4')).toThrow();
    });

    it('should throw NoSuchModelError for embeddingModel', () => {
      const provider = createPixelArt();
      expect(() => provider.embeddingModel('text-embedding-3-small')).toThrow();
    });

    it('should throw NoSuchModelError for textEmbeddingModel', () => {
      const provider = createPixelArt();
      expect(() =>
        provider.textEmbeddingModel('text-embedding-3-small'),
      ).toThrow();
    });
  });

  describe('default provider instance', () => {
    it('pixelArt default export should be a PixelArtProvider', async () => {
      const { pixelArt } = await import('./pixelart-provider');
      expect(pixelArt).toBeDefined();
      expect(typeof pixelArt.image).toBe('function');
      expect(typeof pixelArt.imageModel).toBe('function');
      expect(pixelArt.specificationVersion).toBe('v3');
    });
  });
});

