import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const prompt = 'A pixel art castle at sunset';

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixel-art-v1', {
    provider: 'pixelart.image',
    baseURL: 'https://api.example.com',
    headers: headers ?? (() => ({ Authorization: 'Bearer test-key' })),
    fetch,
    _internal: {
      currentDate,
    },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/images/generations': {
      response: {
        type: 'json-value',
        body: {
          created: 1700000000,
          data: [{ url: 'https://api.example.com/image.png' }],
        },
      },
    },
    'https://api.example.com/image.png': {
      response: {
        type: 'binary',
        body: Buffer.from('test-pixel-art-binary'),
      },
    },
  });

  describe('doGenerate', () => {
    it('should POST to the correct URL', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(server.calls[0].requestMethod).toBe('POST');
      expect(server.calls[0].requestUrl).toBe(
        'https://api.example.com/images/generations',
      );
    });

    it('should download the image from the returned URL', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(server.calls[1].requestMethod).toBe('GET');
      expect(server.calls[1].requestUrl).toBe(
        'https://api.example.com/image.png',
      );
    });

    it('should pass the correct request body with explicit size', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixel-art-v1',
        prompt,
        n: 1,
        size: '256x256',
      });
    });

    it('should use the default size of 512x512 when size is not provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      const requestBody = await server.calls[0].requestBodyJson;
      expect(requestBody.size).toBe('512x512');
    });

    it('should include style from provider options', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { style: 'retro' },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixel-art-v1',
        prompt,
        n: 1,
        size: '512x512',
        style: 'retro',
      });
    });

    it('should include pixelDensity as pixel_density from provider options', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { pixelDensity: 8 },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixel-art-v1',
        prompt,
        n: 1,
        size: '512x512',
        pixel_density: 8,
      });
    });

    it('should include both style and pixelDensity together', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 2,
        size: '1024x1024',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { style: '8bit', pixelDensity: 16 },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixel-art-v1',
        prompt,
        n: 2,
        size: '1024x1024',
        style: '8bit',
        pixel_density: 16,
      });
    });

    it('should spread passthrough provider options into the request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { style: 'pixel', custom_param: 'custom_value' },
        },
      });

      const requestBody = await server.calls[0].requestBodyJson;
      expect(requestBody.custom_param).toBe('custom_value');
    });

    it('should pass headers', async () => {
      const modelWithHeaders = createBasicModel({
        headers: () => ({
          Authorization: 'Bearer my-key',
          'X-Provider-Header': 'provider-value',
        }),
      });

      await modelWithHeaders.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        headers: { 'X-Request-Header': 'request-value' },
      });

      expect(server.calls[0].requestHeaders).toMatchObject({
        authorization: 'Bearer my-key',
        'x-provider-header': 'provider-value',
        'x-request-header': 'request-value',
      });
    });

    it('should return the downloaded image bytes', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBeInstanceOf(Uint8Array);
      expect(Buffer.from(result.images[0] as Uint8Array).toString()).toBe(
        'test-pixel-art-binary',
      );
    });

    it('should return multiple images when n > 1', async () => {
      server.urls['https://api.example.com/images/generations'].response = {
        type: 'json-value',
        body: {
          created: 1700000000,
          data: [
            { url: 'https://api.example.com/image.png' },
            { url: 'https://api.example.com/image.png' },
          ],
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(2);
    });

    it('should handle API errors', async () => {
      server.urls['https://api.example.com/images/generations'].response = {
        type: 'error',
        status: 400,
        body: 'Bad Request',
      };

      const model = createBasicModel();
      await expect(
        model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        }),
      ).rejects.toMatchObject({
        statusCode: 400,
        url: 'https://api.example.com/images/generations',
      });
    });

    describe('warnings', () => {
      it('should warn for unsupported seed', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: 42,
          providerOptions: {},
        });

        expect(result.warnings).toContainEqual({
          type: 'unsupported',
          feature: 'seed',
          details: 'PixelArt does not support the `seed` option.',
        });
      });

      it('should warn for unsupported aspectRatio', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: '16:9',
          seed: undefined,
          providerOptions: {},
        });

        expect(result.warnings).toContainEqual({
          type: 'unsupported',
          feature: 'aspectRatio',
          details:
            'PixelArt does not support the `aspectRatio` option. Use `size` instead.',
        });
      });

      it('should warn for unsupported input files', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          files: [{ type: 'url', url: 'https://example.com/input.png' }],
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        });

        expect(result.warnings).toContainEqual(
          expect.objectContaining({
            type: 'unsupported',
            feature: 'input-files',
          }),
        );
      });

      it('should warn for unsupported mask', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: { type: 'url', url: 'https://example.com/mask.png' },
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        });

        expect(result.warnings).toContainEqual(
          expect.objectContaining({
            type: 'unsupported',
            feature: 'mask',
          }),
        );
      });

      it('should accumulate multiple warnings', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: '16:9',
          seed: 99,
          providerOptions: {},
        });

        expect(result.warnings).toHaveLength(2);
        expect(result.warnings.map((w) => w.feature)).toContain('seed');
        expect(result.warnings.map((w) => w.feature)).toContain('aspectRatio');
      });
    });

    describe('response metadata', () => {
      it('should include timestamp, headers and modelId in response', async () => {
        const testDate = new Date('2024-01-01T00:00:00Z');
        const model = createBasicModel({
          currentDate: () => testDate,
        });

        const result = await model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        });

        expect(result.response).toStrictEqual({
          timestamp: testDate,
          modelId: 'pixel-art-v1',
          headers: expect.any(Object),
        });
      });
    });
  });

  describe('constructor', () => {
    it('should expose correct provider and model information', () => {
      const model = createBasicModel();

      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe('pixel-art-v1');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(4);
    });
  });
});

